/**
 * TradingRouteService — Phase 1 (CRUD)
 *
 * Extracted from TradingControllerV2 to restore service-layer ownership of:
 *   - Route repository access (no AppDataSource.getRepository in controllers)
 *   - Route creation with UEX profit calculation
 *   - Route update / delete with WebSocket side-effects
 *   - calculateRouteRating business logic
 *
 * Phase 2 (analytics) and Phase 3 (UEX external API integration) remain in
 * TradingControllerV2 until their own dedicated extraction slices.
 */

import crypto from 'node:crypto';

import { AppDataSource } from '../../config/database';
import { RouteStatus, TradingRoute } from '../../models/TradingRoute';
import { ConflictError, NotFoundError } from '../../utils/apiErrors';
import { logger } from '../../utils/logger';
import {
  emitRouteCreated,
  emitRouteDeleted,
  emitRouteStatusChanged,
  emitRouteUpdated,
} from '../../websocket/controllers/tradingWebSocketController';

import { UEXPriceFeed } from './trading/UEXPriceFeed';

// ---------------------------------------------------------------------------
// DTOs
// ---------------------------------------------------------------------------

export interface ListOrgRoutesParams {
  limit: number;
  offset: number;
  sort: { field: string; order: 'ASC' | 'DESC' } | null;
  filters: Record<string, string>;
  search: string | null;
  fields: string[] | null;
}

export interface CreateRouteInput {
  name: string;
  description?: string;
  stops?: unknown[];
  estimatedProfit?: number;
  estimatedDuration?: number;
  minCargoCapacity?: number;
  tags?: unknown[];
  notes?: string;
}

export interface ListOrgRoutesResult {
  routes: TradingRoute[];
  total: number;
}

export interface UpdateRouteResult {
  route: TradingRoute;
  statusChanged: boolean;
  oldStatus: RouteStatus;
}

// ---------------------------------------------------------------------------
// Service
// ---------------------------------------------------------------------------

export class TradingRouteService {
  constructor(private readonly uexPriceFeed: UEXPriceFeed) {}

  /**
   * Find a route by ID, optionally scoped to an organization.
   * Returns null when not found (caller decides whether to throw).
   */
  async findById(routeId: string, organizationId?: string): Promise<TradingRoute | null> {
    const routeRepo = AppDataSource.getRepository(TradingRoute);
    const qb = routeRepo.createQueryBuilder('route').where('route.id = :routeId', { routeId });
    if (organizationId) {
      qb.andWhere('route.organizationId = :organizationId', { organizationId });
    }
    return qb.getOne();
  }

  /**
   * List routes belonging to an org with optional filter/search/sort/pagination.
   */
  async listOrgRoutes(orgId: string, params: ListOrgRoutesParams): Promise<ListOrgRoutesResult> {
    const { limit, offset, sort, filters, search } = params;
    const routeRepo = AppDataSource.getRepository(TradingRoute);
    const qb = routeRepo
      .createQueryBuilder('route')
      .where('route.organizationId = :orgId', { orgId });

    if (filters.status) {
      qb.andWhere('route.status = :status', { status: filters.status });
    }
    if (search) {
      qb.andWhere('(route.name ILIKE :search OR route.description ILIKE :search)', {
        search: `%${search}%`,
      });
    }
    if (sort) {
      qb.orderBy(`route.${sort.field}`, sort.order);
    } else {
      qb.orderBy('route.createdAt', 'DESC');
    }

    const total = await qb.getCount();
    const routes = await qb.skip(offset).take(limit).getMany();
    return { routes, total };
  }

  /**
   * Create a new route for an org.
   * Auto-calculates profit from UEX if not provided and stops are present.
   * Emits WebSocket event after save.
   * Throws ConflictError when a route with the same name already exists.
   */
  async createRoute(orgId: string, userId: string, data: CreateRouteInput): Promise<TradingRoute> {
    const routeRepo = AppDataSource.getRepository(TradingRoute);

    const existing = await routeRepo
      .createQueryBuilder('route')
      .where('route.organizationId = :orgId', { orgId })
      .andWhere('route.name = :name', { name: data.name })
      .getOne();

    if (existing) {
      throw new ConflictError('A trading route with this name already exists');
    }

    const normalizedStops = Array.isArray(data.stops) ? data.stops : [];
    let estimatedProfit = data.estimatedProfit;
    if (!estimatedProfit && normalizedStops.length > 0) {
      try {
        estimatedProfit = await this.uexPriceFeed.calculateRouteProfit(normalizedStops);
      } catch (err: unknown) {
        logger.warn('[TradingRouteService.createRoute] UEX profit calculation failed:', err);
      }
    }

    const normalizedTags = Array.isArray(data.tags)
      ? data.tags.filter((tag): tag is string => typeof tag === 'string')
      : [];

    const route = routeRepo.create({
      id: `route_${Date.now()}_${crypto.randomUUID().substring(0, 9)}`,
      creatorId: userId,
      organizationId: orgId,
      name: data.name,
      description: data.description ?? '',
      stops: normalizedStops,
      estimatedProfit,
      estimatedDuration: data.estimatedDuration,
      minCargoCapacity: data.minCargoCapacity,
      status: RouteStatus.ACTIVE,
      tags: normalizedTags,
      notes: data.notes,
      performance: { runCount: 0, avgProfit: 0, avgDuration: 0 },
    });

    await routeRepo.save(route);
    emitRouteCreated(orgId, route as unknown as Parameters<typeof emitRouteCreated>[1]);
    return route;
  }

  /**
   * Apply partial updates to a route and persist.
   * Emits WebSocket events for update and optional status change.
   * Throws NotFoundError when route does not exist or belongs to a different org.
   */
  async updateRoute(
    routeId: string,
    orgId: string,
    updates: Partial<TradingRoute>
  ): Promise<UpdateRouteResult> {
    const route = await this.findById(routeId);
    if (!route || route.organizationId !== orgId) {
      throw new NotFoundError('Trading route not found');
    }

    const oldStatus = route.status;
    const statusChanged = updates.status !== undefined && updates.status !== oldStatus;

    this.applyRouteUpdates(route, updates);

    const routeRepo = AppDataSource.getRepository(TradingRoute);
    await routeRepo.save(route);

    emitRouteUpdated(
      route.organizationId ?? '',
      route as unknown as Parameters<typeof emitRouteUpdated>[1]
    );
    if (statusChanged) {
      emitRouteStatusChanged(route.organizationId ?? '', routeId, oldStatus, route.status);
    }

    return { route, statusChanged, oldStatus };
  }

  /**
   * Remove a route.
   * Throws NotFoundError when route does not exist or belongs to a different org.
   * Emits WebSocket event after removal.
   */
  async deleteRoute(routeId: string, orgId: string): Promise<void> {
    const route = await this.findById(routeId);
    if (!route || route.organizationId !== orgId) {
      throw new NotFoundError('Trading route not found');
    }

    const resolvedOrgId = route.organizationId ?? '';
    const routeRepo = AppDataSource.getRepository(TradingRoute);
    await routeRepo.remove(route);

    emitRouteDeleted(resolvedOrgId, routeId);
  }

  /**
   * Calculate a composite rating (0–10) for a route.
   * Business logic extracted from controller.
   */
  calculateRouteRating(route: TradingRoute): number {
    let rating = 0;

    const profitScore = Math.min((route.estimatedProfit ?? 0) / 20000, 5);
    rating += profitScore;

    if (route.performance) {
      const performanceScore = Math.min(route.performance.runCount / 10, 3);
      rating += performanceScore;
    }

    if (route.estimatedDuration) {
      const durationScore = Math.max(2 - route.estimatedDuration / 120, 0);
      rating += durationScore;
    }

    return Math.min(Math.round(rating * 10) / 10, 10);
  }

  // ---------------------------------------------------------------------------
  // Private helpers
  // ---------------------------------------------------------------------------

  private applyRouteUpdates(route: TradingRoute, updates: Partial<TradingRoute>): void {
    if (updates.name !== undefined) {
      route.name = updates.name;
    }
    if (updates.description !== undefined) {
      route.description = updates.description;
    }
    if (updates.stops !== undefined) {
      route.stops = updates.stops;
    }
    if (updates.estimatedProfit !== undefined) {
      route.estimatedProfit = updates.estimatedProfit;
    }
    if (updates.estimatedDuration !== undefined) {
      route.estimatedDuration = updates.estimatedDuration;
    }
    if (updates.minCargoCapacity !== undefined) {
      route.minCargoCapacity = updates.minCargoCapacity;
    }
    if (updates.status !== undefined) {
      route.status = updates.status;
    }
    if (updates.tags !== undefined) {
      route.tags = updates.tags;
    }
    if (updates.notes !== undefined) {
      route.notes = updates.notes;
    }
  }
}

export const tradingRouteService = new TradingRouteService(new UEXPriceFeed());
